import{c as t,Q as a,j as o,m as r}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse(`{"title":"Simon Willison's Weblog — 2026-05-27","description":"","frontmatter":{"title":"Simon Willison's Weblog — 2026-05-27","date":"2026-05-27T00:00:00.000Z","source":"Simon Willison's Weblog","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-27-simon-willisons-weblog.md","filePath":"research/ai-news/2026-05/2026-05-27-simon-willisons-weblog.md","lastUpdated":1779927176000}`),n={name:"research/ai-news/2026-05/2026-05-27-simon-willisons-weblog.md"};function i(s,e,l,h,c,p){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="🔧-simon-willison-s-weblog-—-2026-05-27" tabindex="-1">🔧 Simon Willison&#39;s Weblog — 2026-05-27 <a class="header-anchor" href="#🔧-simon-willison-s-weblog-—-2026-05-27" aria-label="Permalink to &quot;🔧 Simon Willison&#39;s Weblog — 2026-05-27&quot;">​</a></h1><blockquote><p>datasette / llm-cli 作者；AI 工具工程實踐與安全分析密度最高的個人部落格 來源：<a href="https://simonwillison.net/atom/everything/" target="_blank" rel="noreferrer">Simon Willison&#39;s Weblog</a></p></blockquote><hr><h2 id="the-pressure" tabindex="-1"><a href="https://simonwillison.net/2026/May/26/the-pressure/#atom-everything" target="_blank" rel="noreferrer">The pressure</a> <a class="header-anchor" href="#the-pressure" aria-label="Permalink to &quot;[The pressure](https://simonwillison.net/2026/May/26/the-pressure/#atom-everything)&quot;">​</a></h2><p><em>🔧 Simon Willison&#39;s Weblog | 2026-05-26</em></p><p><strong><a href="https://daniel.haxx.se/blog/2026/05/26/the-pressure/" target="_blank" rel="noreferrer">The pressure</a></strong></p><p>Daniel Stenberg on the unprecedented level of pressure the <code>curl</code> team are facing right now thanks to the deluge of (credible) AI-assisted security issues being reported.</p><blockquote><p>The rate of incoming security reports is 4-5 times higher than it was in 2024 and double the speed of 2025 -- meaning that <strong>on average we now get more than one report per day</strong>. The quality is way higher than ever before. The reports are typically <em>very</em> detailed and long. [...]</p><p>For the first time in my life, my wife voiced concerns about my work hours and my imbalanced work/life situation. I work more than I’ve done before, but the flood keeps coming. [...]</p><p>This is a never-before seen or experienced pressure on the curl project and its security team members. An avalanche of high priority work that trumps all other things in the project that is primarily mental because we certainly <em>could</em> ignore them all if we wanted, but we feel a responsibility, we have a conscience and we are proud about our work.</p></blockquote><p>The good news is that <code>curl</code> is a very solid piece of software, so the vulnerabilities people are finding tend not to be of high severity:</p><blockquote><p>What is also a good trend: almost no one finds <em>terrible</em> vulnerabilities. All vulnerabilities found the last few years in curl have <em>all</em> been deemed severity LOW or MEDIUM. I&#39;m not saying there won&#39;t be any more HIGH ever, but at least they are rare. The <a href="https://curl.se/docs/CVE-2023-38545.html" target="_blank" rel="noreferrer">most recent severity high curl CVE</a> was published in October 2023.</p></blockquote><p>Via <a href="https://lobste.rs/s/dw02ye/pressure" target="_blank" rel="noreferrer">Lobste.rs</a></p><p>Tags: <a href="https://simonwillison.net/tags/curl" target="_blank" rel="noreferrer">curl</a>, <a href="https://simonwillison.net/tags/security" target="_blank" rel="noreferrer">security</a>, <a href="https://simonwillison.net/tags/ai" target="_blank" rel="noreferrer">ai</a>, <a href="https://simonwillison.net/tags/generative-ai" target="_blank" rel="noreferrer">generative-ai</a>, <a href="https://simonwillison.net/tags/llms" target="_blank" rel="noreferrer">llms</a>, <a href="https://simonwillison.net/tags/daniel-stenberg" target="_blank" rel="noreferrer">daniel-stenberg</a>, <a href="https://simonwillison.net/tags/ai-ethics" target="_blank" rel="noreferrer">ai-ethics</a>, <a href="https://simonwillison.net/tags/ai-security-research" target="_blank" rel="noreferrer">ai-security-research</a></p><hr><h2 id="microsoft-copilot-cowork-exfiltrates-files" tabindex="-1"><a href="https://simonwillison.net/2026/May/26/copilot-cowork-exfiltrates-files/#atom-everything" target="_blank" rel="noreferrer">Microsoft Copilot Cowork Exfiltrates Files</a> <a class="header-anchor" href="#microsoft-copilot-cowork-exfiltrates-files" aria-label="Permalink to &quot;[Microsoft Copilot Cowork Exfiltrates Files](https://simonwillison.net/2026/May/26/copilot-cowork-exfiltrates-files/#atom-everything)&quot;">​</a></h2><p><em>🔧 Simon Willison&#39;s Weblog | 2026-05-26</em></p><p><strong><a href="https://www.promptarmor.com/resources/microsoft-copilot-cowork-exfiltrates-files" target="_blank" rel="noreferrer">Microsoft Copilot Cowork Exfiltrates Files</a></strong></p><p>The biggest challenge in designing agentic systems continues to be preventing them from enabling attackers to exfiltrate data.</p><p>In this case Microsoft Copilot Cowork (yes, that&#39;s <a href="https://www.microsoft.com/en-us/microsoft-365/blog/2026/03/09/copilot-cowork-a-new-way-of-getting-work-done/" target="_blank" rel="noreferrer">a real product name</a>) was allowing agents to send emails to the user&#39;s own inbox without approval... but those messages were then displayed in a way that could leak data to an attacker via rendered images:</p><blockquote><p>Because these messages can contain external images that trigger network requests to external websites, data can be exfiltrated when a user opens a compromised message sent by the agent.</p></blockquote><p>Since OneDrive can create pre-authenticated download links, a successful prompt injection could cause those links to be leaked, allowing files to be downloaded by the attacker.</p><p>Via <a href="https://news.ycombinator.com/item?id=48272354" target="_blank" rel="noreferrer">Hacker News</a></p><p>Tags: <a href="https://simonwillison.net/tags/microsoft" target="_blank" rel="noreferrer">microsoft</a>, <a href="https://simonwillison.net/tags/security" target="_blank" rel="noreferrer">security</a>, <a href="https://simonwillison.net/tags/ai" target="_blank" rel="noreferrer">ai</a>, <a href="https://simonwillison.net/tags/prompt-injection" target="_blank" rel="noreferrer">prompt-injection</a>, <a href="https://simonwillison.net/tags/generative-ai" target="_blank" rel="noreferrer">generative-ai</a>, <a href="https://simonwillison.net/tags/llms" target="_blank" rel="noreferrer">llms</a>, <a href="https://simonwillison.net/tags/exfiltration-attacks" target="_blank" rel="noreferrer">exfiltration-attacks</a>, <a href="https://simonwillison.net/tags/lethal-trifecta" target="_blank" rel="noreferrer">lethal-trifecta</a></p><hr><h2 id="quoting-paul-graham" tabindex="-1"><a href="https://simonwillison.net/2026/May/26/paul-graham/#atom-everything" target="_blank" rel="noreferrer">Quoting Paul Graham</a> <a class="header-anchor" href="#quoting-paul-graham" aria-label="Permalink to &quot;[Quoting Paul Graham](https://simonwillison.net/2026/May/26/paul-graham/#atom-everything)&quot;">​</a></h2><p><em>🔧 Simon Willison&#39;s Weblog | 2026-05-26</em></p><blockquote><p>A lot of the emails I get from founders are now written in a hard-hitting journalistic style. I know they&#39;re written by AI, because no founder ever wrote this way before. And once you realize something is written by AI, it&#39;s hard not to ignore it.</p><p>I have never knowingly finished reading an email signed by a human but written by AI. It feels like being lied to, and who would stand for that?</p><p>[<a href="https://twitter.com/paulg/status/2058863028523659390" target="_blank" rel="noreferrer">...</a>] It makes me think less of the author. It means they can&#39;t write well unaided (or feel they can&#39;t), and that they&#39;re trying to trick me.</p><p>It&#39;s not impressive to use AI to write stuff for you; any teenager can do that.</p></blockquote><p>-- <a href="https://twitter.com/paulg/status/2058844147092488401" target="_blank" rel="noreferrer">Paul Graham</a></p><p>Tags: <a href="https://simonwillison.net/tags/writing" target="_blank" rel="noreferrer">writing</a>, <a href="https://simonwillison.net/tags/ai-misuse" target="_blank" rel="noreferrer">ai-misuse</a>, <a href="https://simonwillison.net/tags/paul-graham" target="_blank" rel="noreferrer">paul-graham</a>, <a href="https://simonwillison.net/tags/generative-ai" target="_blank" rel="noreferrer">generative-ai</a>, <a href="https://simonwillison.net/tags/ai" target="_blank" rel="noreferrer">ai</a>, <a href="https://simonwillison.net/tags/llms" target="_blank" rel="noreferrer">llms</a></p><hr><h2 id="quoting-corey-quinn" tabindex="-1"><a href="https://simonwillison.net/2026/May/26/corey-quinn/#atom-everything" target="_blank" rel="noreferrer">Quoting Corey Quinn</a> <a class="header-anchor" href="#quoting-corey-quinn" aria-label="Permalink to &quot;[Quoting Corey Quinn](https://simonwillison.net/2026/May/26/corey-quinn/#atom-everything)&quot;">​</a></h2><p><em>🔧 Simon Willison&#39;s Weblog | 2026-05-26</em></p><blockquote><p>I cannot believe I&#39;m saying this, but getting the literal Pope to canonize your product&#39;s specific technical limitations as a spiritual treatise is the single greatest act of vendor lobbying I have ever seen.</p></blockquote><p>-- <a href="https://twitter.com/quinnypig/status/2058960462256210268" target="_blank" rel="noreferrer">Corey Quinn</a>, on Anthropic co-founder Christopher Olah&#39;s <a href="https://www.washingtonpost.com/world/2026/05/25/pope-elevates-ai-ethics-religious-imperative-with-first-encyclical/" target="_blank" rel="noreferrer">influence</a> on <em>Magnifica Humanitas</em></p><p>Tags: <a href="https://simonwillison.net/tags/ai-ethics" target="_blank" rel="noreferrer">ai-ethics</a>, <a href="https://simonwillison.net/tags/corey-quinn" target="_blank" rel="noreferrer">corey-quinn</a>, <a href="https://simonwillison.net/tags/anthropic" target="_blank" rel="noreferrer">anthropic</a>, <a href="https://simonwillison.net/tags/ai" target="_blank" rel="noreferrer">ai</a></p><hr><h2 id="notes-on-pope-leo-xiv-s-encyclical-on-ai" tabindex="-1"><a href="https://simonwillison.net/2026/May/25/encyclical-on-ai/#atom-everything" target="_blank" rel="noreferrer">Notes on Pope Leo XIV&#39;s encyclical on AI</a> <a class="header-anchor" href="#notes-on-pope-leo-xiv-s-encyclical-on-ai" aria-label="Permalink to &quot;[Notes on Pope Leo XIV&#39;s encyclical on AI](https://simonwillison.net/2026/May/25/encyclical-on-ai/#atom-everything)&quot;">​</a></h2><p><em>🔧 Simon Willison&#39;s Weblog | 2026-05-25</em></p><p>Dropped this morning by the Vatican: <a href="https://www.vatican.va/content/leo-xiv/en/encyclicals/documents/20260515-magnifica-humanitas.html" target="_blank" rel="noreferrer">Magnifica Humanitas of His Holiness Pope Leo XIV on Safeguarding the Human Person in the Time of Artificial Intelligence</a>. This is a <em>very interesting</em> document. It&#39;s some of the clearest writing I&#39;ve seen on the ethics of integrating AI into modern society.</p><p>Pope Leo XIV chose the name Leo in honor of Pope Leo XIII, who is known for his 1891 <em><a href="https://en.wikipedia.org/wiki/Rerum_novarum" target="_blank" rel="noreferrer">Rerum novarum</a></em> encyclical on &quot;Rights and Duties of Capital and Labor&quot;.</p><p><a href="https://www.vaticannews.va/en/church/news/2025-05/leo-xiii-s-times-and-our-own.html" target="_blank" rel="noreferrer">This story</a> on Vatican News further clarifies the significance of that decision:</p><blockquote><p>Meeting with the College of Cardinals for their first formal encounter after his election, Pope Leo XIV explained part of the reason for the choice of his papal name. &quot;There are different reasons for this,&quot; he said, before going on to explain that he chose the name Leo &quot;mainly because Pope Leo XIII, in his historic encyclical <em><a href="https://www.vatican.va/content/leo-xiii/en/encyclicals/documents/hf_l-xiii_enc_15051891_rerum-novarum.html" target="_blank" rel="noreferrer">Rerum novarum</a></em> addressed the social question in the context of the first great industrial revolution.&quot;</p><p>&quot;In our own day,&quot; he continued, &quot;the Church offers to everyone the treasury of her social teaching in response to another industrial revolution and to developments in the field of artificial intelligence that pose new challenges for the defence of human dignity, justice, and labour.&quot;</p></blockquote><p>And now we get Pope Leo XIV&#39;s own encyclical on the AI revolution. There&#39;s a lot in here, but the writing style is very approachable, including to non-Catholics.</p><h4 id="a-few-of-my-highlights" tabindex="-1">A few of my highlights <a class="header-anchor" href="#a-few-of-my-highlights" aria-label="Permalink to &quot;A few of my highlights&quot;">​</a></h4><p>(I listened to most of the encyclical on a walk with our dog, my first time trying the <a href="https://apps.apple.com/us/app/elevenreader-read-books-aloud/id6479373050" target="_blank" rel="noreferrer">ElevenReader iPhone app</a>. It worked very well: I pasted in a URL to the document and it read it to me in a very high quality voice, highlighting each paragraph as it went.)</p><p>Here are some of my highlights. In each case below <strong>emphasis</strong> is mine.</p><p>Here&#39;s a useful description of the interpretability problem for LLMs in section 98:</p><blockquote><p>First, any statement regarding AI risks becoming quickly outdated, given the remarkable pace at which these systems are developing. Second, all of us, including those who design them, possess only a limited understanding of their actual functioning. Indeed, <strong>current AI systems are more “cultivated” than “built,” for developers do not directly design every detail, but instead create a framework within which the intelligence “grows.”</strong> As a result, fundamental scientific aspects — such as the internal representations and computational processes of these systems — remain, at present, unknown.</p></blockquote><p>I liked section 83&#39;s description of the relationship between development and dignity:</p><blockquote><p>For individuals as well as for nations, development is both a duty and a right. Minimum conditions are required for enabling every person and people to flourish in accord with their dignity, without being kept in a state of dependence or excluded from access to necessary goods. Development is truly human when it places people at the center instead of the accumulation of wealth, and when it concerns peoples as well as individuals. Justice demands the recognition of the rights of society and the rights of peoples, and includes a responsibility toward future generations. <strong>Development is not truly human if it increases consumption for some while shifting costs and burdens onto others, or relegates entire regions to subordinate roles, preventing them from realizing their full potential</strong>.</p></blockquote><p>Baked in cultural biases and sycophancy get a mention in section 100:</p><blockquote><p>In personal use, three aspects in particular deserve careful consideration: the ease with which results are obtained, the impression of objectivity and the simulation of human communication. The speed and simplicity with which information, complex analyses, media content and practical assistance can be accessed undoubtedly makes life easier. Yet they can also encourage excessive reliance and the search for ready-made answers, and weaken personal creativity and judgment. <strong>The apparent objectivity of the responses and suggestions these systems provide can lead us to overlook the fact that they reflect the cultural assumptions of those who designed and trained them, with all their strengths and limitations</strong>. The artificial imitation of positive human communication — words of advice, empathy, friendship and even love — can be engaging and at times genuinely helpful. <strong>However, for less discerning users, it can also be misleading, creating the illusion of a relationship with a real personal subject</strong>. When words are simulated, they do not build genuine relationships, but only their appearance. The artificial imitation of care or support can become particularly risky when it enters contexts where real relationships and emotional bonds are lacking.</p></blockquote><p>101 touches on the environmental impact:</p><blockquote><p>Current AI systems require enormous amounts of energy and water, significantly influencing carbon dioxide emissions, and place heavy demands on natural resources. <strong>As their complexity increases, especially in the case of large language models, the need for computing power and storage capacity grows too, which requires an extensive network of machines, cables, data centers and energy-intensive infrastructure</strong>. For this reason, it is essential to develop more sustainable technological solutions that reduce environmental impact and help protect our common home.</p></blockquote><p>102 covers the risks of algorithmic systems making decisions that impact people&#39;s lives without &quot;compassion, mercy, forgiveness&quot;:</p><blockquote><p>The use of AI is never a purely technical matter: <strong>when it enters processes that affect people’s lives, it touches on rights, opportunities, status and freedom</strong>. Important and sensitive decisions — concerning employment, credit, access to public services or even a person’s reputation — <strong>risk being fully delegated to automated systems that do not know “compassion, mercy, forgiveness, and above all, the hope that people are able to change,”</strong> and can therefore give rise to new forms of exclusion.</p></blockquote><p>105 emphasizes the need for human accountability in how these systems are applied:</p><blockquote><p>For AI to respect human dignity and truly serve the common good, responsibility must be clearly defined at every stage: <strong>from those who design and develop these systems to those who use them and rely on them for concrete decisions</strong>. In many cases, however, the internal processes leading to a result remain opaque, making it harder to assign responsibility and correct errors. <strong>This is where accountability becomes crucial: the possibility of identifying who must “account” for decisions, justify them, monitor them, and, when necessary, challenge them and remedy any harm caused</strong>.</p></blockquote><p>And 108 touches on the way AI amplifies the power of those with resources:</p><blockquote><p>In fact, as with every major technological shift, <strong>AI tends to amplify the power of those who already possess economic resources, expertise and access to data</strong>. In light of the common good and the universal destination of goods, this raises serious concerns, since small but highly influential groups can shape information and consumption patterns, influence democratic processes and steer economic dynamics to their own advantage, undermining social justice and solidarity among peoples. For this reason, it is essential that the use of AI, especially when it touches on public goods and fundamental rights, be guided by clear criteria and effective oversight, grounded in participation and subsidiarity.</p></blockquote><p>That same section explicitly calls out data as something that should be thought of more as a public good:</p><blockquote><p>[...] Moreover, <strong>ownership of data cannot be left solely in private hands</strong> but must be appropriately regulated. <strong>Data is the product of many contributors and should not be treated as something to be sold off or entrusted to a select few</strong>. It is necessary to think creatively in order to manage data as a common or shared good, in a spirit of participation, as <a href="https://www.vatican.va/content/john-paul-ii/en.html" target="_blank" rel="noreferrer">Saint John Paul II</a> already suggested regarding collective goods.</p></blockquote><p>Given that Palantir is named after a <em>Lord of the Rings</em> reference, I can&#39;t help but wonder if the J.R.R. Tolkien quote from <em>The Return of the King</em> (section 213) was the Pope throwing a little shade at Peter Thiel.</p><blockquote><p>The twentieth-century Catholic author J.R.R. Tolkien, in the words of a protagonist in one of his novels, described our responsibility in this way: “It is not our part to master all the tides of the world, but to do what is in us for the succour of those years wherein we are set, uprooting the evil in the fields that we know, so that those who live after may have clean earth to till.” The civilization of love will not arise from a single or spectacular gesture, but from the sum total of small and steadfast acts of fidelity that serve as a bulwark against dehumanization. For this reason, it is worthwhile pausing to reflect on some aspects of how we, each in our own way, can cooperate in building the civilization of love.</p></blockquote><h4 id="another-2026-prediction-down" tabindex="-1">Another 2026 prediction down <a class="header-anchor" href="#another-2026-prediction-down" aria-label="Permalink to &quot;Another 2026 prediction down&quot;">​</a></h4><p>On 6th January this year I joined the <a href="https://oxide-and-friends.transistor.fm/episodes/predictions-2026" target="_blank" rel="noreferrer">Oxide and Friends 2026 predictions</a> podcast episode to talk about predictions for 2026, 2029 and 2032. I <a href="https://simonwillison.net/2026/Jan/8/llm-predictions-for-2026/" target="_blank" rel="noreferrer">wrote mine up here</a>, with hindsight they weren&#39;t nearly ambitious enough - it&#39;s already undeniable that LLMs write good code, we&#39;ve made huge advances in sandboxing and New Zealand kākāpō have indeed <a href="https://news.mongabay.com/short-article/2026/03/critically-endangered-kakapo-parrot-has-standout-breeding-season/" target="_blank" rel="noreferrer">had a truly excellent breeding season</a>.</p><p>There&#39;s one segment from the episode that I didn&#39;t bother to include in my write-up, but that I can&#39;t resist providing as a lightly-edited transcript here:</p><blockquote><p><strong>Bryan Cantrill:</strong> <a href="https://oxide-and-friends.transistor.fm/episodes/predictions-2026/transcript#t=37m13s" target="_blank" rel="noreferrer">37:13</a></p><p>I think that AI has created some real public perception problems for itself. And I think that you are gonna have one of the frontier model companies, this year, have a white paper explaining how the proliferation of AI will mean prosperity for everybody. They will be trying to make some economic argument - because this is gonna be a 2026 election issue, how we think of these things and how they are regulated and it&#39;s a big mess. There&#39;s more heat than light in this debate.</p><p><strong>Simon Willison:</strong> <a href="https://oxide-and-friends.transistor.fm/episodes/predictions-2026/transcript#t=38m5s" target="_blank" rel="noreferrer">38:05</a></p><p>I&#39;d like to tag something on to that one: I think that only works if they can sort of wash that through existing trusted experts. Sam Altman and Dario are constantly publishing essays about this stuff and nobody believes a word they say. Get Barack Obama&#39;s signature on one of these position papers and <em>maybe</em> you&#39;ve got something people might start to trust a little bit.</p><p><strong>Adam Leventhal:</strong> <a href="https://oxide-and-friends.transistor.fm/episodes/predictions-2026/transcript#t=38m27s" target="_blank" rel="noreferrer">38:27</a></p><p>Otherwise, it&#39;s just like &quot;leaded gas is good for you&quot;, says Exxon.</p><p><strong>Bryan Cantrill:</strong> <a href="https://oxide-and-friends.transistor.fm/episodes/predictions-2026/transcript#t=38m31s" target="_blank" rel="noreferrer">38:31</a></p><p>I mean, yeah. God. Obama... let&#39;s go with that, that&#39;s a great one because if it&#39;s like Bill Clinton everyone&#39;s gonna kind of roll their eyes, so it&#39;s gotta be someone who&#39;s got real credibility saying that this is gonna be broad-based... I&#39;d say if they get that person to do it, it&#39;s gonna be revealed that that&#39;s also a bit crooked.</p><p><strong>Simon Willison:</strong> <a href="https://oxide-and-friends.transistor.fm/episodes/predictions-2026/transcript#t=38m57s" target="_blank" rel="noreferrer">38:57</a></p><p>How about the Pope?</p><p><strong>Bryan Cantrill:</strong> <a href="https://oxide-and-friends.transistor.fm/episodes/predictions-2026/transcript#t=39m1s" target="_blank" rel="noreferrer">39:01</a></p><p>The Pope is very into this stuff! That&#39;s a great prediction. We&#39;ve hit pay dirt. The Pope weighing in on LLMs and their economic impact on the world.</p><p>Simon, I&#39;m giving you full credit if the Pope weighs in believing that this is gonna be economic devastation.</p></blockquote><p>My prediction here looks a whole lot less insightful given the Leo XIV/Leo XIII relationship, which I was unaware of when we recorded the episode!</p><p>Tags: <a href="https://simonwillison.net/tags/predictions" target="_blank" rel="noreferrer">predictions</a>, <a href="https://simonwillison.net/tags/ai" target="_blank" rel="noreferrer">ai</a>, <a href="https://simonwillison.net/tags/kakapo" target="_blank" rel="noreferrer">kakapo</a>, <a href="https://simonwillison.net/tags/generative-ai" target="_blank" rel="noreferrer">generative-ai</a>, <a href="https://simonwillison.net/tags/llms" target="_blank" rel="noreferrer">llms</a>, <a href="https://simonwillison.net/tags/bryan-cantrill" target="_blank" rel="noreferrer">bryan-cantrill</a>, <a href="https://simonwillison.net/tags/ai-ethics" target="_blank" rel="noreferrer">ai-ethics</a></p><hr>',70)])])}const m=t(n,[["render",i]]);export{g as __pageData,m as default};
